/**
 * Helper class for Min Priority Queue required for Dijkstra's algorithm.
 * Stores elements [priority1, priority2, data...].
 * Comparison prioritizes smaller priority1, then smaller priority2.
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    // Compares two elements based on their priorities (P1, P2)
    // Returns true if element a has higher priority (should come before b)
    _compare(a, b) {
        // Priorities are [T, -C]
        if (a[0] !== b[0]) {
            return a[0] < b[0]; // Smaller T is higher priority
        }
        return a[1] < b[1]; // Smaller -C (i.e., larger C) is higher priority
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _bubbleUp(index) {
        while (index > 0) {
            let parentIndex = Math.floor((index - 1) / 2);
            if (this._compare(this.heap[index], this.heap[parentIndex])) {
                this._swap(index, parentIndex);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        let lastIndex = this.heap.length - 1;
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let smallest = index;

            if (leftChildIndex <= lastIndex && this._compare(this.heap[leftChildIndex], this.heap[smallest])) {
                smallest = leftChildIndex;
            }
            if (rightChildIndex <= lastIndex && this._compare(this.heap[rightChildIndex], this.heap[smallest])) {
                smallest = rightChildIndex;
            }

            if (smallest !== index) {
                this._swap(index, smallest);
                index = smallest;
            } else {
                break;
            }
        }
    }

    push(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    pop() {
        if (this.isEmpty()) return undefined;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }
}


function solve(n, m, sources) {
    // Initialize Time (T) and Color (C) grids
    // Since N*M <= 10^5, we use 2D arrays.

    // T[r][c] stores the minimum time to reach (r, c)
    const T = Array(n).fill(0).map(() => Array(m).fill(Infinity));

    // C[r][c] stores the final color of (r, c)
    const C = Array(n).fill(0).map(() => Array(m).fill(0));

    // Priority Queue stores elements: [time, -color, r, c]
    // MinHeap orders by T first, then by -C (meaning max C)
    const pq = new MinPriorityQueue();

    // 1. Initialization (Seeding the sources)
    for (const source of sources) {
        const r = source[0];
        const c = source[1];
        const color = source[2];

        // Since sources are guaranteed unique, we just initialize them
        T[r][c] = 0;
        C[r][c] = color;
        // Push [time, -color, r, c]
        pq.push([0, -color, r, c]);
    }

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    // 2. Dijkstra/Multi-Source BFS Loop
    while (!pq.isEmpty()) {
        const [t, neg_c, r, c] = pq.pop();
        const current_color = -neg_c;

        // Stale entry check: If we found a strictly better state for (r, c) already, skip.
        // Note: Due to the tie-breaking logic below, we might push duplicates, 
        // but we only process the best known version.
        if (t > T[r][c] || (t === T[r][c] && current_color < C[r][c])) {
            continue;
        }

        // Propagate to neighbors
        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const t_new = t + 1;
                const c_new = current_color;

                const t_old = T[nr][nc];
                const c_old = C[nr][nc];

                // Comparison logic: (t_new, c_new) vs (t_old, c_old)

                if (t_new < t_old) {
                    // Case 1: Strictly faster arrival
                    T[nr][nc] = t_new;
                    C[nr][nc] = c_new;
                    pq.push([t_new, -c_new, nr, nc]);
                } else if (t_new === t_old) {
                    // Case 2: Tie in arrival time
                    if (c_new > c_old) {
                        // Higher color wins the tie
                        C[nr][nc] = c_new;
                        // Update PQ with the new, higher color at the same time
                        pq.push([t_new, -c_new, nr, nc]);
                    }
                    // If c_new <= c_old, the existing color is better or equal, so we do nothing.
                }
                // Case 3: t_new > t_old (Slower arrival), ignore.
            }
        }
    }

    // 3. Format output
    const result = Array(n).fill(0).map(() => Array(m).fill(0));
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < m; c++) {
            result[r][c] = C[r][c];
        }
    }

    return result;
}

