package main

import (
	"container/heap"
	"math"
)

// State represents a cell's status in the priority queue
type State struct {
	T int64 // Time to reach
	C int64 // Color
	R int64 // Row
	C_col int64 // Column (using C_col to avoid conflict with Color C)
}

// PriorityQueue implements heap.Interface and holds States
type PriorityQueue []*State

func (pq PriorityQueue) Len() int { return len(pq) }

// Less defines the priority: Min Time (T), then Max Color (C)
func (pq PriorityQueue) Less(i, j int) bool {
	// Min Time is higher priority
	if pq[i].T != pq[j].T {
		return pq[i].T < pq[j].T
	}
	// Max Color is higher priority (since we are minimizing the comparison,
	// a larger C means it should come first, so we use > here)
	return pq[i].C > pq[j].C
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*State)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

// solve implements the diffusion simulation using Dijkstra's algorithm
func solve(n int64, m int64, sources [][]int64) [][]int64 {
	// Initialize Time (T) grid to infinity
	// T[r][c] stores the minimum time to reach (r, c)
	T := make([][]int64, n)
	// C[r][c] stores the final color of (r, c)
	C_grid := make([][]int64, n)

	infinity := int64(math.MaxInt64)

	for i := int64(0); i < n; i++ {
		T[i] = make([]int64, m)
		C_grid[i] = make([]int64, m)
		for j := int64(0); j < m; j++ {
			T[i][j] = infinity
			C_grid[i][j] = 0
		}
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	// 1. Initialization (Seeding the sources)
	for _, source := range sources {
		r, c, color := source[0], source[1], source[2]

		// Initialize source state
		T[r][c] = 0
		C_grid[r][c] = color

		// Push [time, color, r, c]
		heap.Push(&pq, &State{T: 0, C: color, R: r, C_col: c})
	}

	directions := [][]int64{{0, 1}, {0, -1}, {1, 0}, {-1, 0}}

	// 2. Dijkstra/Multi-Source BFS Loop
	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*State)
		t := item.T
		current_color := item.C
		r := item.R
		c := item.C_col

		// Stale entry check: If we found a strictly better state for (r, c) already, skip.
		// Note: Since we prioritize Min T, then Max C, if the popped state (t, current_color)
		// is worse than the recorded best (T[r][c], C_grid[r][c]), it's stale.
		if t > T[r][c] || (t == T[r][c] && current_color < C_grid[r][c]) {
			continue
		}

		// Propagate to neighbors
		for _, dir := range directions {
			dr, dc := dir[0], dir[1]
			nr := r + dr
			nc := c + dc

			if nr >= 0 && nr < n && nc >= 0 && nc < m {
				t_new := t + 1
				c_new := current_color

				t_old := T[nr][nc]
				c_old := C_grid[nr][nc]

				// Comparison logic: (t_new, c_new) vs (t_old, c_old)

				// Update if:
				// 1. Strictly faster arrival (t_new < t_old)
				// OR
				// 2. Tie in arrival time AND higher color (t_new == t_old && c_new > c_old)

				should_update := false
				if t_new < t_old {
					should_update = true
				} else if t_new == t_old && c_new > c_old {
					should_update = true
				}

				if should_update {
					T[nr][nc] = t_new
					C_grid[nr][nc] = c_new

					// Push the updated state onto the PQ
					heap.Push(&pq, &State{T: t_new, C: c_new, R: nr, C_col: nc})
				}
			}
		}
	}

	// 3. Format output
	result := make([][]int64, n)
	for i := int64(0); i < n; i++ {
		result[i] = make([]int64, m)
		for j := int64(0); j < m; j++ {
			result[i][j] = C_grid[i][j]
		}
	}

	return result
}
