package main

import (
	"container/heap"
	"math"
)

// Item represents an element in the priority queue.
type Item struct {
	time int64
	// negColor stores -color. Since we want to maximize color, minimizing -color achieves this.
	negColor int64 
	r int64
	c int64
}

// PriorityQueue implements heap.Interface and holds Items.
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// Min-heap based on time (T). Smaller T is higher priority.
	if pq[i].time != pq[j].time {
		return pq[i].time < pq[j].time
	}
	// If times are equal, prioritize smaller negColor (i.e., larger positive color).
	return pq[i].negColor < pq[j].negColor
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, m int64, sources [][]int64) [][]int64 {
	// N and M are small enough (product <= 10^5) to use standard int for indexing.
	N := int(n)
	M := int(m)

	// T[r][c] stores the minimum time to reach (r, c)
	T := make([][]int64, N)
	for i := range T {
		T[i] = make([]int64, M)
		for j := range T[i] {
			T[i][j] = math.MaxInt64
		}
	}

	// C[r][c] stores the final color of (r, c)
	C := make([][]int64, N)
	for i := range C {
		C[i] = make([]int64, M)
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	// 1. Initialization (Seeding the sources)
	for _, source := range sources {
		r := int(source[0])
		c := int(source[1])
		color := source[2]

		T[r][c] = 0
		C[r][c] = color

		item := &Item{
			time: 0,
			negColor: -color,
			r: int64(r),
			c: int64(c),
		}
		heap.Push(&pq, item)
	}

	directions := [][2]int{{0, 1}, {0, -1}, {1, 0}, {-1, 0}}

	// 2. Dijkstra/Multi-Source BFS Loop
	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
