package main

import (
	"container/heap"
	"math"
)

// Item structure for the Priority Queue
type Item struct {
	time     int64
	negColor int64 // Negative of the color, used for max-heap behavior on color
	r        int64
	c        int64
}

// PriorityQueue implements heap.Interface and holds Items.
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

// Less determines priority. We want MIN time (T) first, then MAX color (C).
// Since negColor = -C, smaller negColor means larger C.
func (pq PriorityQueue) Less(i, j int) bool {
	if pq[i].time != pq[j].time {
		return pq[i].time < pq[j].time // Min time
	}
	// If times are equal, smaller negColor means higher priority (larger actual color)
	return pq[i].negColor < pq[j].negColor
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x any) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() any {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, m int64, sources [][]int64) [][]int64 {
	// Use a large number for infinity time
	const INF int64 = math.MaxInt64

	// T[r][c] stores the minimum time to reach (r, c)
	T := make([][]int64, n)
	// C[r][c] stores the final color of (r, c)
	C := make([][]int64, n)

	for i := int64(0); i < n; i++ {
		T[i] = make([]int64, m)
		C[i] = make([]int64, m)
		for j := int64(0); j < m; j++ {
			T[i][j] = INF
		}
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	// 1. Initialization (Seeding the sources)
	for _, source := range sources {
		r := source[0]
		c := source[1]
		color := source[2]

		T[r][c] = 0
		C[r][c] = color

		// Push [time, -color, r, c]
		heap.Push(&pq, &Item{
			time:     0,
			negColor: -color,
			r:        r,
			c:        c,
		})
	}

	directions := [][2]int64{{0, 1}, {0, -1}, {1, 0}, {-1, 0}}

	// 2. Dijkstra/Multi-Source BFS Loop
	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		t := item.time
		current_color := -item.negColor
		r := item.r
		c := item.c

		// Stale entry check
		// If we found a strictly better state for (r, c) already, skip.
		// Better means lower T, or same T but higher C.
		// Since the PQ naturally pulls the best state first, we only need to check if the popped state
		// is worse than what's currently recorded.
		if t > T[r][c] || (t == T[r][c] && current_color < C[r][c]) {
			continue
		}

		// Propagate to neighbors
		for _, dir := range directions {
			dr, dc := dir[0], dir[1]
			nr, nc := r+dr, c+dc

			if nr >= 0 && nr < n && nc >= 0 && nc < m {
				t_new := t + 1
				c_new := current_color

				t_old := T[nr][nc]
				c_old := C[nr][nc]

				// Comparison logic: (t_new, c_new) vs (t_old, c_old)

				if t_new < t_old {
					// Case 1: Strictly faster arrival
					T[nr][nc] = t_new
					C[nr][nc] = c_new
					heap.Push(&pq, &Item{
						time:     t_new,
						negColor: -c_new,
						r:        nr,
						c:        nc,
					})
				} else if t_new == t_old {
					// Case 2: Tie in arrival time
					if c_new > c_old {
						// Higher color wins the tie
						C[nr][nc] = c_new
						// Update PQ with the new, higher color at the same time
						heap.Push(&pq, &Item{
							time:     t_new,
							negColor: -c_new,
							r:        nr,
							c:        nc,
						})
					}
				}
				// Case 3: t_new > t_old (Slower arrival), ignore.
			}
		}
	}

	// 3. Format output
	result := make([][]int64, n)
	for i := int64(0); i < n; i++ {
		result[i] = make([]int64, m)
		for j := int64(0); j < m; j++ {
			result[i][j] = C[i][j]
		}
	}

	return result
}

