                    T[nr][nc] = t_new;
                    C[nr][nc] = c_new;
                    pq.push([t_new, -c_new, nr, nc]);
                } else if (t_new === t_old) {
                    // Case 2: Tie in arrival time
                    if (c_new > c_old) {
                        // Higher color wins the tie
                        C[nr][nc] = c_new;
                        // Update PQ with the new, higher color at the same time
                        pq.push([t_new, -c_new, nr, nc]);
                    }
                    // If c_new <= c_old, the existing color is better or equal, so we do nothing.
                }
                // Case 3: t_new > t_old (Slower arrival), ignore.
            }
        }
    }

    // 3. Format output
    const result = Array(n).fill(0).map(() => Array(m).fill(0));
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < m; c++) {
            result[r][c] = C[r][c];
        }
