package main

import (
	"container/heap"
	"math"
)

// Item represents an entry in the priority queue.
type Item struct {
	T    int64 // Time
	NegC int64 // Negative Color (-C)
	R    int64 // Row
	C    int64 // Column
}

// A PriorityQueue implements heap.Interface and holds Items.
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

// Less implements the comparison logic:
// 1. Smaller T has higher priority.
// 2. If T is equal, smaller NegC (i.e., larger C) has higher priority.
func (pq PriorityQueue) Less(i, j int) bool {
	if pq[i].T != pq[j].T {
		return pq[i].T < pq[j].T // Smaller T is better
	}
	// Tie breaker: Smaller NegC is better (since C = -NegC, smaller NegC means larger C)
